head.script:
//==================================================================================================================
// id       : op_302_01_34b
// 이름     : 반출통고목록등록
// 경로     : 물류/작업실적/EDI/세관/반출통고목록등록
// 작 성 자 : 최지수
// 작 업 일 : 2026-04-08
//==================================================================================================================

scwin.dtFm;
scwin.dtTo;

scwin.compCheck = false;
scwin.sendYn = "N"; // 통고여부 : N(대상) / Y(완료)

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function () {

    // 작업장 조회
    $c.sbm.execute(sbm_wrkPlCd);

    const now = new Date();
    const yyyy = now.getFullYear();
    const mm = String(now.getMonth() + 1).padStart(2, '0');
    const dd = String(now.getDate()).padStart(2, '0');

    scwin.dtFm = yyyy + mm + "01";
    scwin.dtTo = yyyy + mm + dd;

    $c.gus.cfDisableObjects([btn_print, btn_send, btn_delete, btn_update, btn_save, tbl_master]);

    acb_lc_wrkPlCd.focus();
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    // udc_fromToCalendar UDC 에 있는 setInitDate 호출
    ica_ed_crryoutNoticeDtFmTo.setInitDate(scwin.dtFm, scwin.dtTo);

    //scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tbl_condition, null);
    acb_lc_wrkPlCd.setSelectedIndex(0);
    ica_ed_crryoutNoticeDtFmTo.setInitDate(scwin.dtFm, scwin.dtTo);  // 일자 setting
    acb_lc_wrkPlCd.focus();
};

//-------------------------------------------------------------------------
// 반출통고목록 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    if (!$c.gus.cfValidate([acb_lc_wrkPlCd, ed_crryoutNoticeDtFrom, ed_crryoutNoticeDtTo])) {	// 작업장, 조회기간
        return;
    }

    if (ed_crryoutNoticeDtFrom.getValue() > ed_crryoutNoticeDtTo.getValue()) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_crryoutNoticeDtTo.focus();
        return;
    }

    // 조회 전 OUT DataList 초기화 처리
    ds_Regist.removeAll();
    ds_RegistDecContents.removeAll();
    ds_ContainerInfo.removeAll();
    //dma_condition.set("crryoutNoticeDtFrom", ed_crryoutNoticeDtFrom.getValue());
    //dma_condition.set("crryoutNoticeDtTo", ed_crryoutNoticeDtTo.getValue());

    scwin.compCheck = false;

    if (lc_sendYn.getValue() == 'Y') {
        scwin.sendYn = "Y";
        $c.sbm.execute(sbm_regist);
        //scwin.set_grid("ds_Regist");
    } else if (lc_sendYn.getValue() == 'N') {
        scwin.sendYn = "N";
        $c.sbm.execute(sbm_registDecContents);
        //scwin.set_grid("ds_RegistDecContents");
    }

};

scwin.set_grid = function (dsId) {

    // gridView 에 dataList 값을 동적으로 넣는 방법은 없기 때문에 아래 3가지 방법이 있다.
    // 1. 아래와 같이 그리드를 직접 그려줌
    // 2. 그리드를 2개 만들어 hidden/show 처리함
    // 3. 컬럼이 동일할 경우 dataList 를 1개만 사용해서 setJson 으로 값을 유동적으로 처리함.
    let gridStr = '<w2:gridView xmlns:w2="http://www.inswave.com/websquare" xmlns:ev="http://www.w3.org/2001/xml-events" '
        + 'dataList="data:' + dsId + '" autoFit="allColumn" checkAllType="false" class="wq_gvw h-full" id="gr_Regist" style="" ev:oncellclick="scwin.gr_Regist_oncellclick">'
        + '<w2:caption id="caption1" style="" value="this is a grid caption."></w2:caption>'
        + '<w2:header id="header1" style="">'
        + '<w2:row id="row1" style="">'
        + '<w2:column displayMode="label" id="column1" inputType="text" style="" value="선택" width="50"></w2:column>'
        + '<w2:column displayMode="label" id="column17" inputType="text" style="" value="MRN" width="150">'
        + '</w2:column>'
        + '<w2:column displayMode="label" id="column15" inputType="text" style="" value="MSN" width="60">'
        + '</w2:column>'
        + '<w2:column displayMode="label" id="column13" inputType="text" style="" value="HSN" width="60">'
        + '</w2:column>'
        + '<w2:column displayMode="label" id="column11" inputType="text" style="" value="처리구분" width="100">'
        + '</w2:column>'
        + '</w2:row>'
        + '</w2:header>'
        + '<w2:gBody id="gBody1" style="">'
        + '<w2:row id="row2" style="">'
        + '<w2:column displayMode="label" id="chk" inputType="checkbox" style="" value="" width="50"></w2:column>'
        + '<w2:column displayMode="label" id="mrn" inputType="text" style="" value="" width="150">'
        + '</w2:column>'
        + '<w2:column displayMode="label" id="msn" inputType="text" style="" value="" width="60">'
        + '</w2:column>'
        + '<w2:column displayMode="label" id="hsn" inputType="text" style="" value="" width="60">'
        + '</w2:column>'
        + '<w2:column displayMode="label" id="procClsNm" inputType="text" style="" value="" width="100">'
        + '</w2:column>'
        + '</w2:row>'
        + '</w2:gBody>'
        + '</w2:gridView>'
        ;

    gr_Regist.setGridStyle(WebSquare.xml.parse(gridStr, true));
};

//-------------------------------------------------------------------------
// 우편번호 팝업
//-------------------------------------------------------------------------
scwin.btn_zip_onclick = async function (e) {
    var options = {
        id: "newzipcodePopup",
        type: "browserPopup",
        modal: true,
        popupName: "우편번호 검색",
        width: 530,
        height: 400
    };

    var popupResult = await $c.win.openPopup("/ui/cm/zz/newzipcodePopup.xml", options, {});

    if (popupResult != null) {
        ed_zip.setValue(popupResult.zip);
        txt_mchtAddr1.setValue(popupResult.addr1);
        txt_mchtAddr2.focus();
    } else {
        ed_zip.setValue("");
        txt_mchtAddr1.setValue("");
        ed_zip.focus();
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    let saveCnt = 0;

    if (lc_sendYn.getValue() == 'N') {  //ds_RegistDecContents
        for (var i = 0; i < ds_Regist.getRowCount(); i++) {
            if (ds_Regist.getCellData(i, "chk") == 1) {
                // 체크된 행으로 포커스 이동 → ref 바인딩 갱신 후 필수값 체크 (ASIS 동일)
                ds_Regist.setRowPosition(i);
                gr_Regist.setFocusedCell(i, 0);
                // ref 바인딩 갱신 대기
                await new Promise(function (r) { setTimeout(r, 50); });
                if (!(await scwin.validateTbl())) {
                    return;
                }
                saveCnt++;
            }
        }

        if (saveCnt == 0) {
            $c.gus.cfAlertMsg("선택된 반출통고목록이 없습니다.");
            return;
        }

        for (var i = 0; i < ds_Regist.getRowCount(); i++) {
            if (ds_Regist.getCellData(i, "chk") == 1) {
                ds_Regist.setCellData(i, "bondZoneCd", dlt_wrkPlCd.getCellData(acb_lc_wrkPlCd.getSelectedIndex(), "bondZoneCd"));
                ds_Regist.setCellData(i, "procClsCd", "3");
            }
        }

        // ds_Regist 변경내용을 ds_RegistDecContents로 동기화 (sbm_save가 ds_RegistDecContents를 전송)
        ds_RegistDecContents.setJSON(ds_Regist.getAllJSON());
        $c.sbm.execute(sbm_save);

    } else {
        for (var i = 0; i < ds_Regist.getRowCount(); i++) {
            if (ds_Regist.getCellData(i, "chk") == 1) {
                ds_Regist.setRowPosition(i);
                gr_Regist.setFocusedCell(i, 0);
                await new Promise(function (r) { setTimeout(r, 50); });
                if (!(await scwin.validateTbl())) {
                    return;
                }
                if (ds_Regist.getCellData(i, "procClsCd") != "3"
                    && ds_Regist.getCellData(i, "procClsCd") != "E") {
                    $c.gus.cfAlertMsg("처리구분이 미전송이거나 오류인경우에만 수정할 수 있습니다.");
                    return;
                }
                saveCnt++;
            }
        }

        if (saveCnt == 0) {
            $c.gus.cfAlertMsg("선택된 반출통고목록이 없습니다.");
            return;
        }

        // for (var i = 0; i < ds_Regist.getRowCount(); i++) {
        // 	if (ds_Regist.getCellData(i, "chk") == 1) {
        // 		ds_Regist.modifyRowStatus(i, 1);
        // 	}
        // }

        $c.sbm.execute(sbm_update);
    }
};

scwin.validateTbl = async function () {
    let ret = await $c.gus.cfValidate([tbl_master]);
    if (!ret) {
        return false;
    }

    var row = ds_Regist.getRowPosition();

    // 기본주소/상세주소: 영문 35자 / 한글 17자 이하 (ASIS 동일)
    var addrCheck = function (val) {
        var hasKorean = false;
        for (var i = 0; i < val.length; i++) {
            if (val.charCodeAt(i) > 127) { hasKorean = true; break; }
        }
        var limit = hasKorean ? 17 : 35;
        return val.length > limit;
    };
    var mchtAddr1 = String(ds_Regist.getCellData(row, "mchtAddr1") || "");
    if (addrCheck(mchtAddr1)) {
        await $c.win.alert("주소은(는) 35자 이하로 입력하십시오. (한글은 17자 이하)");
        txt_mchtAddr1.focus();
        return false;
    }
    var mchtAddr2 = String(ds_Regist.getCellData(row, "mchtAddr2") || "");
    if (addrCheck(mchtAddr2)) {
        await $c.win.alert("주소은(는) 35자 이하로 입력하십시오. (한글은 17자 이하)");
        txt_mchtAddr2.focus();
        return false;
    }

    // 반입중량: Number(16,3) - 정수부 최대 13자리, 소수부 최대 3자리
    var crryinWt = String(ds_Regist.getCellData(row, "crryinWt"));
    if (crryinWt.indexOf(".") >= 0) {
        var parts = crryinWt.split(".");
        var intPart = parts[0].replace("-", "");
        var decPart = parts[1] || "";
        if (decPart.length > 3) {
            await $c.win.alert("반입중량은 소수점 3자리까지만 입력 가능합니다.");
            ed_crryinWt.focus();
            return false;
        }
        if (intPart.length > 13) {
            await $c.win.alert("반입중량은 정수부 13자리 이하로 입력하십시오.");
            ed_crryinWt.focus();
            return false;
        }
    } else {
        var intPart = crryinWt.replace("-", "");
        if (intPart.length > 13) {
            await $c.win.alert("반입중량은 정수부 13자리 이하로 입력하십시오.");
            ed_crryinWt.focus();
            return false;
        }
    }

    return true;
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.btn_update_onclick = function (e) {
    $c.gus.cfDisableObjects([btn_print, btn_send]);
    $c.gus.cfEnableObjects([btn_delete, btn_save, tbl_master]);
};

//-------------------------------------------------------------------------
// 전송
//-------------------------------------------------------------------------
scwin.btn_send_onclick = function (e) {
    let saveCnt = 0;

    for (var i = 0; i < ds_Regist.getRowCount(); i++) {
        if (ds_Regist.getCellData(i, "chk") == 1) {
            ds_Regist.setCellData(i, "chk", 0);
            if (ds_Regist.getRowStatus(i) == 3) {
                ds_Regist.setCellData(i, "chk", 1);
                ds_Regist.setRowPosition(i);
                $c.gus.cfAlertMsg("변경된 반출통고목록이 있습니다.\n먼저 저장하시기 바랍니다.");
                for (var j = 0; j < ds_Regist.getRowCount(); j++) {
                    ds_Regist.setCellData(j, "chk", 0);
                    if (ds_Regist.getRowStatus(j) == 3) {
                        ds_Regist.setCellData(j, "chk", 1);
                    }
                }
                $c.gus.cfDisableObjects([btn_print, btn_send]);
                $c.gus.cfEnableObjects([btn_delete, btn_save, tbl_master]);
                return;
            }
            ds_Regist.setCellData(i, "chk", 1);
            saveCnt++;
        }
    }

    if (saveCnt == 0) {
        $c.gus.cfAlertMsg("선택된 반출통고목록이 없습니다.");
        return;
    }

    for (var i = 0; i < ds_Regist.getRowCount(); i++) {
        if (ds_Regist.getCellData(i, "chk") == 1) {
            ds_Regist.setCellData(i, "procClsCd", "0");
            ds_Regist.setCellData(i, "procClsNm", "전송대기");
        }
    }

    $c.sbm.execute(sbm_send);
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.btn_delete_onclick = function (e) {
    let saveCnt = 0;

    for (var i = 0; i < ds_Regist.getRowCount(); i++) {
        if (ds_Regist.getCellData(i, "chk") == 1) {
            if (ds_Regist.getCellData(i, "procClsCd") != "3"
                && ds_Regist.getCellData(i, "procClsCd") != "E") {
                $c.gus.cfAlertMsg("처리구분이 미전송이거나 오류인경우에만 삭제할 수 있습니다.");
            }
            saveCnt++;
        }
    }

    if (saveCnt == 0) {
        $c.gus.cfAlertMsg("선택된 반출통고목록이 없습니다.");
        return;
    }

    // for (var i = 0; i < ds_Regist.getRowCount(); i++) {
    // 	if (ds_Regist.getCellData(i, "chk") == 1) {
    // 		ds_Regist.modifyRowStatus(i, 1);
    // 	}
    // }

    //tr_Delete.Post();
    $c.sbm.execute(sbm_delete);
};



//-------------------------------------------------------------------------
// submitdone Start
//-------------------------------------------------------------------------
scwin.sbm_regist_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code == 0) {
        grp_totalCnt.setStyle("display", "");

        if (ds_Regist.getRowCount() == 0) {
            $c.gus.cfAlertMsg("[반출통고목록] " + MSG_CM_ERR_003);
            $c.gus.cfDisableObjects([btn_print, btn_send, btn_delete, btn_update, btn_save, tbl_master]);
            totalRows.setValue(ds_Regist.getRowCount());
            return;
        }

        totalRows.setValue(ds_Regist.getRowCount());
        $c.gus.cfDisableObjects([btn_send, btn_update, btn_delete, btn_save, tbl_master]);
        $c.gus.cfEnableObjects([btn_print]);
        scwin.compCheck = true;

        // 처리구분이 "오류"인 행의 MRN 셀에 밑줄+손모양 커서 적용 (ASIS: fontstyle=under, cursor=hand)
        scwin.f_applyMrnStyle();

        gr_Regist.setFocusedCell(0, 0);
    }
    else {
        ds_Regist.removeAll();
    }
};

scwin.applyDefaultCustoms = function (rows) {
    const idx = acb_lc_wrkPlCd.getSelectedIndex();
    const bondZoneCd = dlt_wrkPlCd.getCellData(idx, "bondZoneCd") || "";
    const bondZoneNm = dlt_wrkPlCd.getCellData(idx, "bondZoneNm") || "";

    return rows.map(row => ({
        ...row,
        cstmCd: row.cstmCd || bondZoneCd.substring(0, 3),
        cstmNm: row.cstmNm || bondZoneNm,
        cstmSecCd: row.cstmSecCd || "D8",
        cstmSecNm: row.cstmSecNm || "통관과"
    }));
};

scwin.sbm_registDecContents_submitdone = function (e) {

    if (e.responseJSON.resultDataSet[0].Code == 0) {
        const rows = scwin.applyDefaultCustoms(ds_RegistDecContents.getAllJSON());
        ds_Regist.setJSON(rows);
        // setJSON 후 rowStatus 초기화 (변경 안 했는데 변경상태로 표시되는 현상 방지)
        ds_Regist.modifyAllStatus("R");

        grp_totalCnt.setStyle("display", "");
        totalRows.setValue(ds_Regist.getRowCount());

        if (ds_Regist.getRowCount() == 0) {
            $c.gus.cfAlertMsg("[반출통고목록] " + MSG_CM_ERR_003);
            $c.gus.cfDisableObjects([btn_print, btn_send, btn_delete, btn_update]);
            $c.gus.cfEnableObjects([btn_save, tbl_master]);
            scwin.compCheck = true;
            return;
        }

        $c.gus.cfDisableObjects([btn_print, btn_send, btn_delete, btn_update]);
        $c.gus.cfEnableObjects([btn_save, tbl_master]);
        scwin.compCheck = true;

        ds_Regist.setRowPosition(0);
        gr_Regist.setFocusedCell(0, 0, true);
    }
};

scwin.sbm_containerInfo_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        grp_totalCnt_container.setStyle("display", "");
        totalRows1.setValue(ds_ContainerInfo.getRowCount());
    }
    else {
        ds_ContainerInfo.removeAll();
    }
};

scwin.sbm_save_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
        $c.sbm.execute(sbm_registDecContents);
    }
};

scwin.sbm_update_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        $c.gus.cfAlertMsg(MSG_CM_INF_003);	// 성공적으로 수정하였습니다
        $c.sbm.execute(sbm_regist);
    }
};

scwin.sbm_send_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        $c.gus.cfAlertMsg("성공적으로 전송하였습니다.");
        $c.sbm.execute(sbm_regist);
    }
};

scwin.sbm_delete_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        $c.gus.cfAlertMsg(MSG_CM_INF_004);	// 성공적으로 삭제하였습니다
        $c.sbm.execute(sbm_regist);
    }
};
scwin.sbm_wrkPlCd_submitdone = function (e) {
    dlt_wrkPlCd.sort("wrkPlCd", 0);  // wrkPlCd 오름차순 정렬 (0:오름차순, 1:내림차순)
};
//-------------------------------------------------------------------------
// submitdone End
//-------------------------------------------------------------------------

//-------------------------------------------------------------------------
// 컴포넌트 이벤트 Start
//-------------------------------------------------------------------------
scwin.ds_Regist_onrowpositionchange = function (info) {

    let row = ds_Regist.getRowPosition();

    if (row < 0) return;

    if (scwin.sendYn == "Y") {
        // 버튼 상태 처리 (ASIS 동일)
        if (ds_Regist.getCellData(row, "procClsCd") == "3"
            || ds_Regist.getCellData(row, "procClsCd") == "E") {
            $c.gus.cfDisableObjects([btn_save, tbl_master]);
            $c.gus.cfEnableObjects([btn_print, btn_send, btn_delete, btn_update]);
        }
        else {
            $c.gus.cfDisableObjects([btn_print, btn_send, btn_delete, btn_update, btn_save, tbl_master]);
            $c.gus.cfEnableObjects([btn_print]);
        }
    }
    else {
        // sendYn=N(대상): 발행/전송/삭제/수정 비활성, 저장만 활성 (U권한 시 자동)
        $c.gus.cfDisableObjects([btn_print, btn_send, btn_delete, btn_update]);
        $c.gus.cfEnableObjects([btn_save, tbl_master]);

        // 통관정보 세팅 (ASIS 동일)
        ed_cstmCd.setValue(dlt_wrkPlCd.getCellData(acb_lc_wrkPlCd.getSelectedIndex(), "bondZoneCd").substr(0, 3));
        txt_cstmNm.setValue(dlt_wrkPlCd.getCellData(acb_lc_wrkPlCd.getSelectedIndex(), "bondZoneNm"));
        ed_cstmSecCd.setValue("D8");
        txt_cstmSecNm.setValue("통관과");
    }

    // 컨테이너 정보 조회 (ASIS: 양쪽 분기 모두 실행)
    dma_condition1.set("mrn", ds_Regist.getCellData(row, "mrn"));
    dma_condition1.set("msn", ds_Regist.getCellData(row, "msn"));
    dma_condition1.set("hsn", ds_Regist.getCellData(row, "hsn"));
    dma_condition1.set("wrkPlCd", dma_condition.get("wrkPlCd"));

    $c.sbm.execute(sbm_containerInfo);
};

scwin.ds_RegistDecContents_onrowpositionchange = function (info) {

    if (info.newRowIndex == 0 && scwin.compCheck) {
        //return;
    }

    ed_cstmCd.setValue(dlt_wrkPlCd.getCellData(acb_lc_wrkPlCd.getSelectedIndex() + 1, "bondZoneCd"));
    txt_cstmNm.setValue(dlt_wrkPlCd.getCellData(acb_lc_wrkPlCd.getSelectedIndex() + 1, "bondZoneNm"));
    ed_cstmSecCd.setValue("D8");
    txt_cstmSecNm.setValue("통관과");

    dma_condition1.set("mrn", ds_RegistDecContents.getCellData(info.newRowIndex, "mrn"));
    dma_condition1.set("msn", ds_RegistDecContents.getCellData(info.newRowIndex, "msn"));
    dma_condition1.set("hsn", ds_RegistDecContents.getCellData(info.newRowIndex, "hsn"));
    dma_condition1.set("wrkPlCd", dma_condition.get("wrkPlCd"));

    $c.sbm.execute(sbm_containerInfo);
};

scwin.lc_sendYn_onchange = function (info) {
    ds_Regist.removeAll();
    ds_RegistDecContents.removeAll();
    ds_ContainerInfo.removeAll();
    totalRows.setValue(0);
    totalRows1.setValue(0);
    $c.gus.cfDisableObjects([btn_print, btn_send, btn_delete, btn_update, btn_save, tbl_master]);
};

scwin.btn_print_onclick = async function (e) {
    console.log("=== btn_print_onclick 시작 ===");
    var printMode = chb_printCheck.getValue() == "1";
    var previewMode = chb_previewCheck.getValue() == "1";
    console.log("printMode(인쇄옵션):", printMode, "previewMode(미리보기):", previewMode);

    var printCnt = 0;

    for (var i = 0; i < ds_Regist.getRowCount(); i++) {
        if (ds_Regist.getCellData(i, "chk") == 1) {
            var odiName = "";
            var reportPath = "";

            if (acb_lc_wrkPlCd.getValue() == "4P08" || acb_lc_wrkPlCd.getValue() == "4P13") {
                odiName = "op_302_01_30r2";
                reportPath = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_30r2.ozr";
            } else {
                odiName = "op_302_01_30r";
                reportPath = "/ds/op/wrkrslts/yardwrkrslts/op_302_01_30r.ozr";
            }

            var odiParam = {
                crryoutNoticeDt: ds_Regist.getCellData(i, "crryoutNoticeDt"),
                wrkPlCd: ds_Regist.getCellData(i, "wrkPlCd"),
                mrn: ds_Regist.getCellData(i, "mrn"),
                msn: ds_Regist.getCellData(i, "msn"),
                hsn: ds_Regist.getCellData(i, "hsn")
            };

            var formParam = {
                odiName: odiName
            };

            var viewerParam = {
                zoom: 100,
                useprogressbar: false
            };

            // 인쇄옵션: 독립적으로 printMode 결정
            var printOpt = printMode ? "view" : "silent";

            console.log("선택 행[" + i + "] odiName:", odiName, "reportPath:", reportPath);
            console.log("odiParam:", JSON.stringify(odiParam), "printOpt:", printOpt);

            var data = {
                reportName: reportPath,
                odiParam: odiParam,
                viewerParam: viewerParam,
                formParam: formParam
            };

            if (previewMode) {
                // 미리보기 체크 → preview 모드
                viewerParam.useprogressbar = true;
                viewerParam.mode = "preview";
                var opts = {
                    type: "viewer",
                    printMode: printOpt
                };
                console.log("[미리보기] printOpt:", printOpt);
                $c.ext.openOzReport(data, opts);
            } else {
                // 미리보기 미체크 → print 모드
                var opts = {
                    printMode: printOpt
                };
                console.log("[인쇄] printOpt:", printOpt);
                $c.ext.printOzReport(data, opts);
            }

            printCnt++;
        }
    }

    console.log("=== btn_print_onclick 종료 === printCnt:", printCnt);
    if (printCnt == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_007, ["발행할 반출통고목록"]);
        return;
    }
};

scwin.gr_Regist_oncellclick = function (rowIndex, columnIndex, columnId) {
    if (rowIndex >= 0) {
        if (columnId == "mrn") {
            if (ds_Regist.getCellData(rowIndex, "procClsNm") == "오류") {
                scwin.f_errorPopUp(rowIndex);
            }
        }
    }
};
//-------------------------------------------------------------------------
// 컴포넌트 이벤트 End
//-------------------------------------------------------------------------

// 처리구분이 "오류"인 행의 MRN 셀에 밑줄+손모양 커서 적용
scwin.f_applyMrnStyle = function () {
    for (var i = 0; i < ds_Regist.getRowCount(); i++) {
        if (ds_Regist.getCellData(i, "procClsNm") == "오류") {
            gr_Regist.setCellStyle(i, "mrn", "text-decoration", "underline");
            gr_Regist.setCellStyle(i, "mrn", "cursor", "pointer");
        }
    }
};

// 오류팝업 오픈
scwin.f_errorPopUp = function (row) {
    var width = 860, height = 580;
    var sFeatures = "dialogWidth:" + width + "px;"
        + "dialogHeight:" + height + "px;"
        + "center:Yes;help:No;resizable:No;status:No;scroll:No";

    var deg = 0;
    var docCd = "5II";
    var declarNo = "";

    var mrn = ds_Regist.getCellData(ds_Regist.getRowPosition(), "mrn");
    var msn = ds_Regist.getCellData(ds_Regist.getRowPosition(), "msn");
    var hsn = ds_Regist.getCellData(ds_Regist.getRowPosition(), "hsn");

    if (msn.length < 2) {
        msn = "000" + msn;
    } else if (msn.length < 3) {
        msn = "00" + msn;
    } else if (msn.length < 4) {
        msn = "0" + msn;
    }

    if (hsn == 0) {
        declarNo = mrn + msn;
    } else if (hsn.length < 2) {
        declarNo = mrn + msn + "000" + hsn;
    } else if (hsn.length < 3) {
        declarNo = mrn + msn + "00" + hsn;
    } else if (hsn.length < 4) {
        declarNo = mrn + msn + "0" + hsn;
    } else if (hsn.length < 5) {
        declarNo = mrn + msn + hsn;
    }

    // sURL = "/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.jsp?deg=" + deg
    //         + "&docCd=" + docCd
    //         + "&declarNo=" + declarNo;
    // window.showModalDialog(sURL,null,sFeatures);

    var data = {
        deg: deg
        , docCd: docCd
        , declarNo: declarNo
        , callbackFn: scwin.callBackFunc
    };

    var opts = {
        id: "smpPop"
        , popupName: "보세운송오류내역상세조회"
        , modal: true
        , type: "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title: "Win pop"  //Layer pop
        , width: 860
        , height: 580
    };

    $c.win.openPopup("/ui/ds/sd/odrmgnt/odrprewrk/sd_401_05_04p.xml", opts, data);
};

scwin.callBackFunc = function (ret) {
};

// 공통 팝업 호출 (case별 UDC/코드/명 매핑)
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1: // 선박
            udc_vssl.cfCommonPopUp(scwin.f_popupCallback(1), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
            break;
        case 2: // 화주상호
            udc_clntNo.cfCommonPopUp(scwin.f_popupCallback(2), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
            break;
        case 3: // 신고세관
            udc_cstm.cfCommonPopUp(scwin.f_popupCallback(3), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
            break;
        case 4: // 신고과
            udc_cstmSec.cfCommonPopUp(scwin.f_popupCallback(4), pCode, pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch);
            break;
    }
};

// 공통 팝업 콜백
scwin.f_popupCallback = function (disGubun) {
    return function (rtnList) {
        switch (disGubun) {
            case 1: // 선박
                cfSetReturnValue(rtnList, ed_vsslCd, txt_vsslNm);
                break;
            case 2: // 화주상호
                cfSetReturnValue(rtnList, ed_clntNo, txt_mchtNmCmpy);
                break;
            case 3: // 신고세관
                cfSetReturnValue(rtnList, ed_cstmCd, txt_cstmNm);
                break;
            case 4: // 신고과
                cfSetReturnValue(rtnList, ed_cstmSecCd, txt_cstmSecNm);
                break;
        }
    };
};

// 팝업 리턴값 세팅
function cfSetReturnValue(rtnList, codeObj, nameObj) {
    if (rtnList != null && rtnList[0] != "N/A") {
        codeObj.setValue(rtnList[0]);
        nameObj.setValue(rtnList[1]);
    }
}

